  height: 140px;
  position: absolute;
  right: 32%;
  bottom: -11px;
  background: var(--loader-bg, #e8e8e8);
  transform: translateZ(200px) rotate(var(--r));
  animation: darma-loader-darma-custom-775-mask var(--duration) linear forwards infinite;
}

