.darma-loader-darma-custom-665__ai-matrix-loader {color: var(--loader-color, #00ff88);

  width: 120px;
  height: 160px;
  margin: 0;
  position: relative;
  perspective: 800px;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 5px;
}

.darma-loader-darma-custom-665__digit {
  color: var(--loader-color, #00ff88);
  font-family: monospace;
  font-size: 18px;
  text-align: center;
  text-shadow: 0 0 5px var(--loader-color, #00ff88);
  animation:
    darma-loader-darma-custom-665-matrix-fall 2s infinite,
    darma-loader-darma-custom-665-matrix-flicker 0.5s infinite;
  opacity: 0;
}

.darma-loader-darma-custom-665__digit:nth-child(1) {
  animation-delay: 0.1s;
}
.darma-loader-darma-custom-665__digit:nth-child(2) {
  animation-delay: 0.3s;
}
.darma-loader-darma-custom-665__digit:nth-child(3) {
  animation-delay: 0.5s;
}
.darma-loader-darma-custom-665__digit:nth-child(4) {
  animation-delay: 0.7s;
}
.darma-loader-darma-custom-665__digit:nth-child(5) {
  animation-delay: 0.9s;
}
.darma-loader-darma-custom-665__digit:nth-child(6) {
  animation-delay: 1.1s;
}
.darma-loader-darma-custom-665__digit:nth-child(7) {
  animation-delay: 1.3s;
}
.darma-loader-darma-custom-665__digit:nth-child(8) {
  animation-delay: 1.5s;
}

.darma-loader-darma-custom-665__glow {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(
    circle,
    color-mix(in srgb, var(--loader-color, #00ff88) 10%, transparent) 0%,
    transparent 70%
  );
  animation: darma-loader-darma-custom-665-matrix-pulse 2s infinite;
}

@keyframes darma-loader-darma-custom-665-matrix-fall {
  0% {
    transform: translateY(-50px) rotateX(90deg);
